import { Clock, GitBranch } from 'lucide-react';
import { Chip, sig } from './ds';

const FLOW = [
  { step: 'Input',   sub: 'Voice · File · Text' },
  { step: 'STT',     sub: 'OpenAI Whisper' },
  { step: 'Extract', sub: 'Ticker & context' },
  { step: 'Data',    sub: 'Market signals' },
  { step: 'Claude',  sub: 'Reasoning & reply' },
];

export default function Sidebar({ history, onSelect, activeTab }) {
  return (
    <aside style={{
      background: 'var(--white)', borderLeft: '1px solid var(--rule)',
      display: 'flex', flexDirection: 'column',
    }}>

      {/* Pipeline visual */}
      <div style={{ padding: '16px 14px', borderBottom: '1px solid var(--rule)' }}>
        <div style={{ display: 'flex', alignItems: 'center', gap: 6, marginBottom: 12 }}>
          <GitBranch size={12} color='var(--ink-4)' strokeWidth={2} />
          <span style={{ fontSize: 10, fontWeight: 700, color: 'var(--ink-4)', letterSpacing: '0.09em', textTransform: 'uppercase' }}>
            Pipeline
          </span>
        </div>
        {FLOW.map((f, i) => (
          <div key={i} style={{ display: 'flex', alignItems: 'flex-start', gap: 8 }}>
            <div style={{ display: 'flex', flexDirection: 'column', alignItems: 'center', width: 14, flexShrink: 0, paddingTop: 3 }}>
              <div style={{ width: 5, height: 5, borderRadius: '50%', background: 'var(--ink-5)', flexShrink: 0 }} />
              {i < FLOW.length - 1 && <div style={{ width: 1, height: 16, background: 'var(--rule)', marginTop: 2 }} />}
            </div>
            <div style={{ paddingBottom: i < FLOW.length - 1 ? 0 : 0, paddingTop: 0 }}>
              <p style={{ fontSize: 12, fontWeight: 500, color: 'var(--ink-2)', margin: 0, lineHeight: 1.3 }}>{f.step}</p>
              <p style={{ fontSize: 10.5, color: 'var(--ink-5)', margin: '1px 0 10px' }}>{f.sub}</p>
            </div>
          </div>
        ))}
      </div>

      {/* Active mode */}
      <div style={{ padding: '10px 14px', borderBottom: '1px solid var(--rule)', background: 'var(--paper)' }}>
        <p style={{ fontSize: 10, fontWeight: 700, color: 'var(--ink-4)', letterSpacing: '0.09em', textTransform: 'uppercase', marginBottom: 7 }}>Input mode</p>
        <div style={{ display: 'flex', gap: 4 }}>
          {['text','record','upload'].map(t => (
            <span key={t} style={{
              padding: '3px 9px', borderRadius: 'var(--r)',
              fontSize: 11, fontWeight: 500,
              background: activeTab === t ? 'var(--ink)' : 'transparent',
              color: activeTab === t ? '#fff' : 'var(--ink-4)',
              border: `1px solid ${activeTab === t ? 'var(--ink)' : 'transparent'}`,
              textTransform: 'capitalize', transition: 'all 0.2s',
            }}>
              {t}
            </span>
          ))}
        </div>
      </div>

      {/* History */}
      <div style={{ flex: 1, overflowY: 'auto', padding: '14px' }}>
        <div style={{ display: 'flex', alignItems: 'center', gap: 6, marginBottom: 11 }}>
          <Clock size={12} color='var(--ink-4)' strokeWidth={2} />
          <span style={{ fontSize: 10, fontWeight: 700, color: 'var(--ink-4)', letterSpacing: '0.09em', textTransform: 'uppercase' }}>
            History {history.length > 0 && `· ${history.length}`}
          </span>
        </div>

        {history.length === 0 ? (
          <p style={{ fontSize: 12, color: 'var(--ink-5)', lineHeight: 1.7, textAlign: 'center', padding: '24px 0' }}>
            No analyses yet.
          </p>
        ) : (
          <div style={{ display: 'flex', flexDirection: 'column', gap: 3 }}>
            {history.map((item, i) => {
              const tone = item.signal === 'BULLISH' ? 'bull' : item.signal === 'BEARISH' ? 'bear' : 'flat';
              return (
                <button
                  key={i}
                  onClick={() => onSelect(item)}
                  style={{
                    padding: '10px 11px', background: 'var(--paper)',
                    border: '1px solid var(--rule)',
                    borderRadius: 'var(--r)', cursor: 'pointer',
                    fontFamily: 'var(--f-ui)', textAlign: 'left',
                    transition: 'all 0.12s', outline: 'none',
                    animation: i === 0 ? 'up 0.22s ease' : 'none',
                  }}
                  onMouseEnter={e => { e.currentTarget.style.borderColor = 'var(--rule-2)'; e.currentTarget.style.background = 'var(--white)'; }}
                  onMouseLeave={e => { e.currentTarget.style.borderColor = 'var(--rule)'; e.currentTarget.style.background = 'var(--paper)'; }}
                >
                  <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', marginBottom: 4 }}>
                    <span style={{ fontSize: 14, fontWeight: 600, color: 'var(--ink)', fontFamily: 'var(--f-data)' }}>
                      {item.ticker}
                    </span>
                    <Chip tone={tone}>{item.signal}</Chip>
                  </div>
                  <p style={{ fontSize: 11, color: 'var(--ink-3)', overflow: 'hidden', textOverflow: 'ellipsis', whiteSpace: 'nowrap', margin: '0 0 4px' }}>
                    {item.transcript?.slice(0, 45)}…
                  </p>
                  <div style={{ display: 'flex', justifyContent: 'space-between' }}>
                    <span style={{ fontFamily: 'var(--f-data)', fontSize: 12, fontWeight: 600, color: 'var(--ink-2)' }}>{item.price}</span>
                    <span style={{ fontSize: 10.5, color: 'var(--ink-4)' }}>{item.time}</span>
                  </div>
                </button>
              );
            })}
          </div>
        )}
      </div>
    </aside>
  );
}
